import{_ as t,o,c as l,ai as a}from"./chunks/framework.DMjte4z8.js";const k=JSON.parse('{"title":"如何把地图发布到KK平台：完整上传步骤","description":"","frontmatter":{"title":"如何把地图发布到KK平台：完整上传步骤","category":"publishing","updated":"2026-05-07T00:00:00.000Z","model":"manual","quality_score":0.9,"discovered_via":"manual"},"headers":[],"relativePath":"publishing/如何把地图发布到kk平台完整上传步骤.md","filePath":"publishing/如何把地图发布到kk平台完整上传步骤.md","lastUpdated":1778155425000}'),e={name:"publishing/如何把地图发布到kk平台完整上传步骤.md"};function i(n,r,s,d,g,h){return o(),l("div",null,[...r[0]||(r[0]=[a('<h1 id="如何把地图发布到kk平台-完整上传步骤" tabindex="-1">如何把地图发布到KK平台：完整上传步骤 <a class="header-anchor" href="#如何把地图发布到kk平台-完整上传步骤" aria-label="Permalink to “如何把地图发布到KK平台：完整上传步骤”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>本文介绍如何将用 <strong>War3 World Editor（WE/KKWE）</strong> 制作的 <code>.w3x</code> / <code>.w3m</code> 地图文件，上传并发布到 KK 官方对战平台（create.kkdzpt.com），让其他玩家可以玩到你的作品。</p><blockquote><p><strong>💡 前提条件</strong>：</p><ul><li>已注册 KK 开发者账号（前往 <a href="https://create.kkdzpt.com" target="_blank" rel="noreferrer">create.kkdzpt.com</a> 注册）</li><li>地图已在 World Editor 中制作完成并保存为 <code>.w3x</code> 格式</li><li>建议先在本地测试地图无明显 bug 后再上传</li></ul></blockquote><hr><h2 id="第一步-准备地图文件" tabindex="-1">第一步：准备地图文件 <a class="header-anchor" href="#第一步-准备地图文件" aria-label="Permalink to “第一步：准备地图文件”">​</a></h2><h3 id="_1-1-保存并压缩地图" tabindex="-1">1.1 保存并压缩地图 <a class="header-anchor" href="#_1-1-保存并压缩地图" aria-label="Permalink to “1.1 保存并压缩地图”">​</a></h3><p>在 World Editor 中完成地图后：</p><ol><li>点击菜单 <strong>「文件」→「另存为」</strong></li><li>选择保存格式为 <strong><code>.w3x</code></strong>（魔兽争霸III自定义地图格式）</li><li>勾选 <strong>「压缩存储」</strong> 选项，减小文件体积</li><li>建议地图文件命名为英文或数字，避免中文路径导致上传失败</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：保存时不勾选压缩，导致地图文件过大被平台拒绝。KK 平台对地图大小有限制，建议控制在 <strong>8MB 以内</strong>。</p></blockquote><h3 id="_1-2-准备封面图和介绍图" tabindex="-1">1.2 准备封面图和介绍图 <a class="header-anchor" href="#_1-2-准备封面图和介绍图" aria-label="Permalink to “1.2 准备封面图和介绍图”">​</a></h3><ul><li><strong>封面图</strong>：建议尺寸 <strong>400×300px</strong>，JPG 格式，展示地图的核心玩法或场景</li><li><strong>介绍图</strong>：可多张，用于在地图大厅展示给玩家</li></ul><hr><h2 id="第二步-登录-kk-开发者平台" tabindex="-1">第二步：登录 KK 开发者平台 <a class="header-anchor" href="#第二步-登录-kk-开发者平台" aria-label="Permalink to “第二步：登录 KK 开发者平台”">​</a></h2><ol><li>打开浏览器访问 <a href="https://create.kkdzpt.com" target="_blank" rel="noreferrer">https://create.kkdzpt.com</a></li><li>点击右上角 <strong>「登录」</strong>，使用 KK 账号登录</li><li>登录后点击顶部导航栏的 <strong>「地图管理」</strong></li></ol><hr><h2 id="第三步-创建地图项目" tabindex="-1">第三步：创建地图项目 <a class="header-anchor" href="#第三步-创建地图项目" aria-label="Permalink to “第三步：创建地图项目”">​</a></h2><ol><li>在「地图管理」页面点击 <strong>「创建地图」</strong> 或 <strong>「+新建」</strong></li><li>填写基本信息： <ul><li><strong>地图名称</strong>：你的地图中文名（玩家在大厅看到的名称）</li><li><strong>游戏类型</strong>：选择 <strong>War3</strong></li><li><strong>地图简介</strong>：200字以内，吸引玩家点击</li></ul></li><li>上传封面图和介绍图</li><li>点击 <strong>「保存」</strong> 创建项目</li></ol><blockquote><p><strong>💡 新手提示</strong>：地图名称和简介是吸引玩家的第一印象，认真填写，避免使用「测试」「test」等词汇，会影响推荐权重。</p></blockquote><hr><h2 id="第四步-上传地图文件" tabindex="-1">第四步：上传地图文件 <a class="header-anchor" href="#第四步-上传地图文件" aria-label="Permalink to “第四步：上传地图文件”">​</a></h2><ol><li>进入刚创建的地图项目页面</li><li>点击 <strong>「版本管理」→「上传新版本」</strong></li><li>选择你的 <code>.w3x</code> 地图文件</li><li>填写版本信息： <ul><li><strong>版本号</strong>：建议从 <code>1.0.0</code> 开始，格式为 <code>主版本.次版本.修订号</code></li><li><strong>更新说明</strong>：简述这个版本新增或修复了什么</li></ul></li><li>点击 <strong>「提交」</strong> 上传</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：上传了错误的文件格式。注意：</p><ul><li>✅ 正确：<code>.w3x</code>（魔兽争霸III地图）</li><li>❌ 错误：<code>.w3m</code>（旧格式，部分功能受限）</li><li>❌ 错误：<code>header.map</code>（这是 Y3 编辑器的文件，与 WE 无关）</li></ul></blockquote><hr><h2 id="第五步-申请审核" tabindex="-1">第五步：申请审核 <a class="header-anchor" href="#第五步-申请审核" aria-label="Permalink to “第五步：申请审核”">​</a></h2><ol><li>上传完成后，在版本管理页面找到刚上传的版本</li><li>点击 <strong>「申请审核」</strong> 按钮</li><li>审核期间可以继续在本地开发，<strong>不影响线上运行中的旧版本</strong></li><li>审核通过后，你会收到站内消息通知</li><li>收到通过通知后，点击 <strong>「发布上线」</strong> 让玩家看到新版本</li></ol><blockquote><p><strong>💡 审核时间</strong>：一般为 <strong>1-3个工作日</strong>。如长时间未审核，可在 KK 开发者群联系审核管理员。</p></blockquote><hr><h2 id="第六步-测试验证" tabindex="-1">第六步：测试验证 <a class="header-anchor" href="#第六步-测试验证" aria-label="Permalink to “第六步：测试验证”">​</a></h2><p>在正式申请审核前，建议先用<strong>测试版本</strong>在平台上自测：</p><ol><li>上传地图后选择 <strong>「设为测试版本」</strong> 而不是直接申请审核</li><li>在 KK 客户端中找到自己的地图，进入<strong>测试房间</strong></li><li>确认地图正常加载、无崩溃后再申请审核</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：跳过测试直接发布，结果玩家进入后发现严重 bug，收到大量差评影响地图排名。</p></blockquote><hr><h2 id="版本管理说明" tabindex="-1">版本管理说明 <a class="header-anchor" href="#版本管理说明" aria-label="Permalink to “版本管理说明”">​</a></h2><p>KK 平台维护三个版本状态：</p><table tabindex="0"><thead><tr><th>版本类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>线上版本</strong></td><td>所有玩家当前看到并游玩的版本</td></tr><tr><td><strong>审核版本</strong></td><td>正在等待平台审核的版本（唯一，同时只能有一个）</td></tr><tr><td><strong>测试版本</strong></td><td>开发者自测用，不影响线上版本</td></tr></tbody></table><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to “常见问题”">​</a></h2><p><strong>Q：上传后玩家搜不到我的地图？</strong> A：新地图需要通过审核后才会出现在大厅搜索结果中。审核通过且点击「发布上线」后约30分钟生效。</p><p><strong>Q：地图文件太大被拒绝怎么办？</strong> A：在 World Editor 中用「文件→另存为」时勾选「压缩存储」，并检查是否导入了过多大尺寸自定义模型/音效。</p><p><strong>Q：需要开发者认证才能上传吗？</strong> A：普通 War3 地图上传不需要特殊认证，注册 KK 账号即可。若需开通商城、存档等高级功能，需联系 KK 官方开通权限。</p>',41)])])}const p=t(e,[["render",i]]);export{k as __pageData,p as default};
